### Rust Implementation

```rust
// src/pages/analytics.rs
use chrono::{DateTime, Utc, NaiveDate};
use std::collections::HashMap;

pub struct AnalyticsGenerator {
    db: Connection,
}

impl AnalyticsGenerator {
    pub fn generate_all(&self) -> Result<AnalyticsBundle, Error> {
        info\!("Generating pre-computed analytics...");

        let statistics = self.generate_statistics()?;
        let timeline = self.generate_timeline()?;
        let workspace_summary = self.generate_workspace_summary()?;
        let agent_summary = self.generate_agent_summary()?;
        let top_terms = self.generate_top_terms()?;

        Ok(AnalyticsBundle {
            statistics,
            timeline,
            workspace_summary,
            agent_summary,
            top_terms,
        })
    }

    fn generate_statistics(&self) -> Result<Statistics, Error> {
        // Fast aggregate queries
        let total_conversations: i64 = self.db.query_row(
            "SELECT COUNT(*) FROM conversations",
            [],
            |row| row.get(0)
        )?;

        let total_messages: i64 = self.db.query_row(
            "SELECT COUNT(*) FROM messages",
            [],
            |row| row.get(0)
        )?;

        let agents: HashMap<String, AgentStats> = self.db.query_map(
            "SELECT agent, COUNT(*) as conv_count, 
                    (SELECT COUNT(*) FROM messages m 
                     JOIN conversations c ON m.conversation_id = c.id 
                     WHERE c.agent = conversations.agent) as msg_count
             FROM conversations
             GROUP BY agent",
            [],
            |row| Ok((row.get(0)?, AgentStats {
                conversations: row.get(1)?,
                messages: row.get(2)?,
            }))
        )?.collect()?;

        let time_range = self.db.query_row(
            "SELECT MIN(started_at), MAX(started_at) FROM conversations",
            [],
            |row| Ok((row.get::<_, Option<i64>>(0)?, row.get::<_, Option<i64>>(1)?))
        )?;

        Ok(Statistics {
            total_conversations: total_conversations as usize,
            total_messages: total_messages as usize,
            agents,
            time_range: TimeRange {
                earliest: time_range.0.map(DateTime::from_timestamp_millis).flatten(),
                latest: time_range.1.map(DateTime::from_timestamp_millis).flatten(),
            },
            computed_at: Utc::now(),
        })
    }

    fn generate_timeline(&self) -> Result<Timeline, Error> {
        // Daily message counts
        let daily: Vec<DailyEntry> = self.db.query_map(
            "SELECT DATE(started_at/1000, unixepoch) as date,
                    COUNT(*) as msg_count,
                    COUNT(DISTINCT conversation_id) as conv_count
             FROM messages m
             JOIN conversations c ON m.conversation_id = c.id
             GROUP BY date
             ORDER BY date",
            [],
            |row| Ok(DailyEntry {
                date: row.get(0)?,
                messages: row.get(1)?,
                conversations: row.get(2)?,
            })
        )?.collect()?;

        // Aggregate to weekly and monthly
        let weekly = aggregate_to_weekly(&daily);
        let monthly = aggregate_to_monthly(&daily);

        Ok(Timeline { daily, weekly, monthly })
    }

    fn generate_top_terms(&self) -> Result<TopTerms, Error> {
        // Extract common terms from conversation titles
        let titles: Vec<String> = self.db.query_map(
            "SELECT title FROM conversations WHERE title IS NOT NULL",
            [],
            |row| row.get(0)
        )?.collect()?;

        let mut term_counts: HashMap<String, usize> = HashMap::new();
        for title in titles {
            for word in title.split_whitespace() {
                let word = word.to_lowercase();
                if word.len() >= 3 && \!STOP_WORDS.contains(&word.as_str()) {
                    *term_counts.entry(word).or_insert(0) += 1;
                }
            }
        }

        let mut top: Vec<_> = term_counts.into_iter().collect();
        top.sort_by(|a, b| b.1.cmp(&a.1));
        top.truncate(100);

        Ok(TopTerms { terms: top })
    }
}
```

### Browser Usage

```javascript
// web/src/dashboard.js

class Dashboard {
    constructor(analytics) {
        this.stats = analytics.statistics;
        this.timeline = analytics.timeline;
        this.workspaces = analytics.workspace_summary.workspaces;
    }

    render() {
        // Instant render - no database queries needed
        this.renderOverview();
        this.renderTimeline();
        this.renderAgentBreakdown();
        this.renderWorkspaceList();
    }

    renderOverview() {
        document.getElementById("total-conversations").textContent = 
            this.stats.total_conversations.toLocaleString();
        document.getElementById("total-messages").textContent = 
            this.stats.total_messages.toLocaleString();
    }

    renderTimeline() {
        // Sparkline using pre-computed data
        const data = this.timeline.daily.slice(-30);
        renderSparkline("timeline-chart", data);
    }
}
